import{_ as o,o as c,c as d,as as a}from"./chunks/framework.Dt0DMeWU.js";const b=JSON.parse('{"title":"koa 框架","description":"","frontmatter":{},"headers":[],"relativePath":"frontend/Nodejs重学/07-koa框架.md","filePath":"frontend/Nodejs重学/07-koa框架.md","lastUpdated":1775485159000}'),l={name:"frontend/Nodejs重学/07-koa框架.md"};function i(t,e,s,p,r,n){return c(),d("div",null,[...e[0]||(e[0]=[a('<h1 id="koa-框架" tabindex="-1"><code>koa</code> 框架 <a class="header-anchor" href="#koa-框架" aria-label="Permalink to &quot;`koa` 框架&quot;">​</a></h1><blockquote><p>前面我们已经学习了 <code>express</code>，另外一个非常流行的 <code>Node Web</code> 服务器框架就是 <code>Koa</code>。</p></blockquote><blockquote><p><code>Koa</code> 官方的介绍：</p></blockquote><ul><li><p><code>koa</code>：<code>next generation web framework for node.js</code>；</p></li><li><p><code>koa</code>：<code>node.js</code> 的下一代 <code>web</code> 框架；</p><blockquote><p>事实上，<code>koa</code> 是 <code>express</code> 同一个团队开发的一个新的 <code>Web</code> 框架：</p></blockquote></li><li><p>目前团队的 <code> 核心开发者 TJ 的主要精力也在维护 Koa</code>，<code>express</code> 已经交给团队维护了；</p></li><li><p><code>Koa</code> 旨在为 <code>Web</code> 应用程序和 <code>API</code> 提供 <code>更小、更丰富和更强大的能力</code>；</p></li><li><p>相 <code>对于 express 具有更强</code> 的异步处理能力（后续我们再对比）；</p></li><li><p><code>Koa 的核心代码只有 1600+行 </code>，是一个 <code>更加轻量级的框架</code>；</p></li><li><p>我们 <code>可以根据需要安装和使用中间件</code>；</p></li></ul><blockquote><p>事实上学习了 <code>express</code> 之后，学习 <code>koa</code> 的过程是很简单的；</p></blockquote><h2 id="koa-初体验" tabindex="-1"><code>Koa</code> 初体验 <a class="header-anchor" href="#koa-初体验" aria-label="Permalink to &quot;`Koa` 初体验&quot;">​</a></h2><blockquote><p>我们来体验一下 <code>koa</code> 的 <code>Web</code> 服务器，创建一个接口。</p></blockquote><ul><li><code>koa</code> 也是通过注册中间件来完成请求操作的；</li></ul><blockquote><p><code>koa</code> 注册的中间件提供了两个参数：</p></blockquote><blockquote><p><code>ctx</code>：上下文（<code>Context</code>）对象；</p></blockquote><ul><li><p><code>koa</code> 并没有像 <code>express</code> 一样，将 <code>req</code> 和 <code>res</code> 分开，而是将它们作为 <code>ctx</code> 的属性；</p></li><li><p><code>ctx</code> 代表一次请求的上下文对象；</p></li><li><p><code>ctx.request</code>：获取请求对象；</p></li><li><p><code>ctx.response</code>：获取响应对象；</p><blockquote><p><code>next</code>：本质上是一个 <code>dispatch</code>，类似于之前的 <code>next</code>；</p></blockquote></li><li><p>后续我们学习 <code>Koa</code> 的源码，来看一下它是一个怎么样的函数</p></li></ul><p><img src="https://img.xbin.cn/images/2023/10/10-20-31-b7bd06.png" alt=""></p><h2 id="koa-中间件" tabindex="-1"><code>Koa</code> 中间件 <a class="header-anchor" href="#koa-中间件" aria-label="Permalink to &quot;`Koa` 中间件&quot;">​</a></h2><blockquote><p><code>koa</code> 通过创建的 <code>app</code> 对象，注册中间件只能通过 <code>use</code> 方法：</p></blockquote><ul><li><code>Koa</code> 并 <code>没有提供methods的方式来注册中间件</code>；</li><li>也 <code>没有提供path中间件来匹配路径</code>；</li></ul><blockquote><p>但是真实开发中我们如何将路径和 <code>method</code> 分离呢？</p></blockquote><ul><li>方式一：根据 <code>request自己来判断 </code>；</li><li>方式二：使用 <code>第三方路由中间件</code>；</li></ul><p><img src="https://img.xbin.cn/images/2023/10/10-20-32-a262bf.png" alt=""></p><h2 id="路由的使用" tabindex="-1">路由的使用 <a class="header-anchor" href="#路由的使用" aria-label="Permalink to &quot;路由的使用&quot;">​</a></h2><blockquote><p><code>koa</code> 官方并没有给我们提供路由的库，我们可以选择第三方库：<code>koa-router</code></p></blockquote><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @koa/router</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><blockquote><p>我们可以先封装一个 <code>user.router.js</code> 的文件：</p></blockquote><blockquote><p>在 <code>app</code> 中将 <code>router.routes()</code> 注册为中间件：</p></blockquote><blockquote><p>注意：<code>allowedMethods</code> 用于判断某一个 <code>method</code> 是否支持：</p></blockquote><ul><li>如果我们请求 <code>get</code>，那么是正常的请求，因为我们有实现 <code>get</code>；</li><li>如果我们请求 <code>put</code>、<code>delete</code>、<code>patch</code>，那么就自动报错：<code>Method Not Allowed</code>，状态码：<code>405</code>；</li><li>如果我们请求 <code>link</code>、<code>copy</code>、<code>lock</code>，那么久自动报错：<code>Not Implemented</code>，状态码：<code>501</code>；</li></ul><p><img src="https://img.xbin.cn/images/2023/10/10-20-33-03671c.png" alt=""></p><p><img src="https://img.xbin.cn/images/2023/10/10-20-34-ab4f2b.png" alt=""></p><h2 id="参数解析-params-query" tabindex="-1">参数解析：<code>params</code> - <code>query</code> <a class="header-anchor" href="#参数解析-params-query" aria-label="Permalink to &quot;参数解析：`params` - `query`&quot;">​</a></h2><blockquote><p>请求地址：<code>http://localhost:8000/users/123</code></p></blockquote><ul><li>获取 <code>params</code>：</li></ul><p><img src="https://img.xbin.cn/images/2023/10/10-20-37-fe4b2e.png" alt=""></p><blockquote><p>请求地址：<code>http://localhost:8000/login?username=why&amp;password=123</code></p></blockquote><ul><li>获取 <code>query</code>：</li></ul><p><img src="https://img.xbin.cn/images/2023/10/10-20-37-f94acf.png" alt=""></p><h2 id="参数解析-json" tabindex="-1">参数解析：<code>json</code> <a class="header-anchor" href="#参数解析-json" aria-label="Permalink to &quot;参数解析：`json`&quot;">​</a></h2><blockquote><p>请求地址：<code>http://localhost:8000/login</code></p></blockquote><blockquote><p><code>body</code> 是 <code>json</code> 格式</p></blockquote><p><img src="https://img.xbin.cn/images/2023/10/10-20-38-52ed4c.png" alt=""></p><blockquote><p>获取 <code>json</code> 数据：</p></blockquote><ul><li>安装依赖： <code>npm install koa-bodyparser</code>;</li><li>使用 <code>koa-bodyparser</code> 的中间件；</li></ul><p><img src="https://img.xbin.cn/images/2023/10/10-20-39-bb7e2a.png" alt=""></p><h2 id="参数解析-x-www-form-urlencoded" tabindex="-1">参数解析：<code>x-www-form-urlencoded</code> <a class="header-anchor" href="#参数解析-x-www-form-urlencoded" aria-label="Permalink to &quot;参数解析：`x-www-form-urlencoded`&quot;">​</a></h2><blockquote><p>请求地址：<code>http://localhost:8000/login</code></p></blockquote><ul><li><code>body</code> 是 <code>x-www-form-urlencoded</code> 格式：</li></ul><p><img src="https://img.xbin.cn/images/2023/10/10-20-39-3509ba.png" alt=""></p><blockquote><p>获取 <code>json</code> 数据：(和 <code>json</code> 是一致的)</p></blockquote><ul><li>安装依赖： <code>npm install koa-bodyparser</code>;</li><li>使用 <code>koa-bodyparser</code> 的中间件；</li></ul><p><img src="https://img.xbin.cn/images/2023/10/10-20-40-6f5acd.png" alt=""></p><h2 id="参数解析-form-data" tabindex="-1">参数解析：<code>form-data</code> <a class="header-anchor" href="#参数解析-form-data" aria-label="Permalink to &quot;参数解析：`form-data`&quot;">​</a></h2><blockquote><p>请求地址：<code>http://localhost:8000/login</code></p></blockquote><ul><li><code>body</code> 是 <code>form-data</code> 格式</li></ul><p><img src="https://img.xbin.cn/images/2023/10/10-20-41-b30ca2.png" alt=""></p><blockquote><p>解析 <code>body</code> 中的数据，我们需要使用 <code>multer</code></p></blockquote><ul><li>安装依赖：<code>npm install koa-multer</code>;</li><li>使用 <code>multer</code> 中间件；</li></ul><p><img src="https://img.xbin.cn/images/2023/10/10-20-41-65db76.png" alt=""></p><h2 id="multer-上传文件" tabindex="-1"><code>Multer</code> 上传文件 <a class="header-anchor" href="#multer-上传文件" aria-label="Permalink to &quot;`Multer` 上传文件&quot;">​</a></h2><p><img src="https://img.xbin.cn/images/2023/10/10-20-42-40c837.png" alt=""></p><h2 id="静态服务器" tabindex="-1">静态服务器 <a class="header-anchor" href="#静态服务器" aria-label="Permalink to &quot;静态服务器&quot;">​</a></h2><blockquote><p><code>koa</code> 并没有内置部署相关的功能，所以我们需要使用第三方库：</p></blockquote><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> koa-static</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>部署的过程类似于 <code>express</code>：</li></ul><p><img src="https://img.xbin.cn/images/2023/10/10-20-43-ed3414.png" alt=""></p><h2 id="数据的响应" tabindex="-1">数据的响应 <a class="header-anchor" href="#数据的响应" aria-label="Permalink to &quot;数据的响应&quot;">​</a></h2><blockquote><p>输出结果：<code>body</code> 将响应主体设置为以下之一：</p></blockquote><ul><li><code>string</code> ：字符串数据</li><li><code>Buffer</code> ：<code>Buffer</code> 数据</li><li><code>Stream</code> ：流数据</li><li><code>Object</code>|| <code>Array</code>：对象或者数组</li><li><code>null</code> ：不输出任何内容</li><li>如果 <code>response.status</code> 尚未设置，<code>Koa</code> 会自动将状态设置为 <code>200</code> 或 <code>204</code>。</li></ul><blockquote><p>请求状态：<code>status</code></p></blockquote><p><img src="https://img.xbin.cn/images/2023/10/10-20-43-3f3075.png" alt=""></p><h2 id="错误处理" tabindex="-1">错误处理 <a class="header-anchor" href="#错误处理" aria-label="Permalink to &quot;错误处理&quot;">​</a></h2><p><img src="https://img.xbin.cn/images/2023/10/10-20-44-4dfb0f.png" alt=""></p><h2 id="创建-koa-的过程" tabindex="-1">创建 <code>Koa</code> 的过程 <a class="header-anchor" href="#创建-koa-的过程" aria-label="Permalink to &quot;创建 `Koa` 的过程&quot;">​</a></h2><p><img src="https://img.xbin.cn/images/2023/10/10-20-44-a030f2.png" alt=""></p><h2 id="开启监听" tabindex="-1">开启监听 <a class="header-anchor" href="#开启监听" aria-label="Permalink to &quot;开启监听&quot;">​</a></h2><p><img src="https://img.xbin.cn/images/2023/10/10-20-45-f4a58f.png" alt=""></p><h2 id="注册中间件" tabindex="-1">注册中间件 <a class="header-anchor" href="#注册中间件" aria-label="Permalink to &quot;注册中间件&quot;">​</a></h2><p><img src="https://img.xbin.cn/images/2023/10/10-20-45-82e0cd.png" alt=""></p><h2 id="监听回调" tabindex="-1">监听回调 <a class="header-anchor" href="#监听回调" aria-label="Permalink to &quot;监听回调&quot;">​</a></h2><p><img src="https://img.xbin.cn/images/2023/10/10-20-45-4814cb.png" alt=""></p><h2 id="compose-方法" tabindex="-1"><code>compose</code> 方法 <a class="header-anchor" href="#compose-方法" aria-label="Permalink to &quot;`compose` 方法&quot;">​</a></h2><p><img src="https://img.xbin.cn/images/2023/10/10-20-46-871d9f.png" alt=""></p><h2 id="和-express-对比" tabindex="-1">和 <code>express</code> 对比 <a class="header-anchor" href="#和-express-对比" aria-label="Permalink to &quot;和 `express` 对比&quot;">​</a></h2><blockquote><p>在学习了两个框架之后，我们应该已经可以发现 <code>koa</code> 和 <code>express</code> 的区别：</p></blockquote><blockquote><p>从架构设计上来说：</p></blockquote><blockquote><p><code>express</code> 是完整和强大的，其中帮助我们内置了非常多好用的功能；</p></blockquote><blockquote><p><code>koa</code> 是简洁和自由的，它只包含最核心的功能，并不会对我们使用其他中间件进行任何的限制。</p></blockquote><ul><li>甚至是在 <code>app</code> 中连最基本的 <code>get</code>、<code>post</code> 都没有给我们提供；</li><li>我们需要通过自己或者路由来判断请求方式或者其他功能；</li></ul><blockquote><p>因为 <code>express</code> 和 <code>koa</code> 框架他们的核心其实都是中间件：</p></blockquote><ul><li>但是他们的中间件事实上，它们的中间件的执行机制是不同的，特别是针对某个中间件中包含异步操作时；</li><li>所以，接下来，我们再来研究一下 <code>express</code> 和 <code>koa</code> 中间件的执行顺序问题；</li></ul><h2 id="案例实现" tabindex="-1">案例实现 <a class="header-anchor" href="#案例实现" aria-label="Permalink to &quot;案例实现&quot;">​</a></h2><blockquote><p>我通过一个需求来演示所有的过程：</p></blockquote><ul><li>假如有三个中间件会在一次请求中匹配到，并且按照顺序执行；</li><li>我希望最终实现的方案是：✓ 在 <code>middleware1</code> 中，在 <code>req.message</code> 中添加一个字符串 <code>aaa</code>；✓ 在 <code>middleware2</code> 中，在 <code>req.message</code> 中添加一个 字符串 <code>bbb</code>；✓ 在 <code>middleware3</code> 中，在 <code>req.message</code> 中添加一个 字符串 <code>ccc</code>；✓ 当所有内容添加结束后，在 <code>middleware1</code> 中，通过 <code>res</code> 返回最终的结果；</li></ul><blockquote><p>实现方案：</p></blockquote><ul><li><code>Express</code> 同步数据的实现；</li><li><code>Express</code> 异步数据的实现；</li><li><code>Koa</code> 同步数据的实现；</li><li><code>Koa</code> 异步数据的实现； <blockquote><p>具体的代码查看课堂演练</p></blockquote></li></ul><h2 id="koa-洋葱模型" tabindex="-1"><code>koa</code> 洋葱模型 <a class="header-anchor" href="#koa-洋葱模型" aria-label="Permalink to &quot;`koa` 洋葱模型&quot;">​</a></h2><p>两层理解含义：</p><ul><li>中间件处理代码的过程；</li><li><code>Response</code> 返回 <code>body</code> 执行；</li></ul><p><img src="https://img.xbin.cn/images/2023/10/10-20-47-352d4b.png" alt=""></p>',96)])])}const h=o(l,[["render",i]]);export{b as __pageData,h as default};
